225: func (cm *containerManagerImpl) GetNodeAllocatableReservation() v1.ResourceList {
226: 	evictionReservation := hardEvictionReservation(cm.nodeConfig.HardEvictionThresholds, cm.capacity)
227: 	result := make(v1.ResourceList)
228: 	for k := range cm.capacity {
229: 		value := resource.NewQuantity(0, resource.DecimalSI)
230: 		if cm.nodeConfig.SystemReserved != nil {
231: 			value.Add(cm.nodeConfig.SystemReserved[k])
232: 		}
233: 		if cm.nodeConfig.KubeReserved != nil {
234: 			value.Add(cm.nodeConfig.KubeReserved[k])
235: 		}
236: 		if evictionReservation != nil {
237: 			value.Add(evictionReservation[k])
238: 		}
239: 		if !value.IsZero() {
240: 			result[k] = *value
241: 		}
242: 	}
243: 	return result
